// ---------------------------------------------------------------------------
// Minimal Express-compatible request/response types (no @types/express needed)
// ---------------------------------------------------------------------------

interface Req {
  params: Record<string, string>;
  body: Record<string, unknown>;
}

interface Res {
  status(code: number): Res;
  json(body: unknown): Res;
}

// ---------------------------------------------------------------------------
// Domain types
// ---------------------------------------------------------------------------

export interface User {
  id: string;
  email: string;
  [key: string]: unknown;
}

export interface UserRepository {
  findById(id: string): Promise<User | null>;
  findByEmail(email: string): Promise<User | null>;
  updateEmail(id: string, email: string): Promise<User>;
}

// ---------------------------------------------------------------------------
// Email validation
// ---------------------------------------------------------------------------

/**
 * Returns true when the string has a valid local@domain.tld shape.
 * Intentionally simple — rejects anything without exactly one @,
 * a non-empty local part, and a domain containing at least one dot.
 */
export function isValidEmail(email: unknown): email is string {
  if (typeof email !== 'string') return false;
  const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return EMAIL_RE.test(email);
}

// ---------------------------------------------------------------------------
// Handler factory
// ---------------------------------------------------------------------------

/**
 * Returns an Express route handler for PATCH /users/:id/email.
 *
 * The UserRepository is injected so the handler remains testable in isolation.
 *
 * Error response shape: { error: { code: string; message: string } }
 * Success response shape: the full User object returned by the repository.
 */
export function makePatchUserEmailHandler(userRepository: UserRepository) {
  return async function patchUserEmail(req: Req, res: Res): Promise<Res> {
    const { id } = req.params;
    const { email } = req.body;

    // AC3: Validate email format before any DB look-ups
    if (!isValidEmail(email)) {
      return res.status(400).json({
        error: {
          code: 'INVALID_EMAIL_FORMAT',
          message: 'The provided email address is not valid.',
        },
      });
    }

    // AC4: Verify the target user exists
    const currentUser = await userRepository.findById(id);
    if (!currentUser) {
      return res.status(404).json({
        error: {
          code: 'USER_NOT_FOUND',
          message: `No user found with id '${id}'.`,
        },
      });
    }

    // AC5: Idempotent — if the email hasn't changed, return the existing user as-is
    if (currentUser.email === email) {
      return res.status(200).json(currentUser);
    }

    // AC2: Ensure the new email is not already claimed by a different user
    const conflictingUser = await userRepository.findByEmail(email);
    if (conflictingUser) {
      return res.status(409).json({
        error: {
          code: 'EMAIL_ALREADY_IN_USE',
          message: 'That email address is already associated with another account.',
        },
      });
    }

    // AC1: Perform the update and return the updated user
    const updatedUser = await userRepository.updateEmail(id, email);
    return res.status(200).json(updatedUser);
  };
}

