    const repo = makeRepo({ user: ALICE }); // ALICE.email = 'alice@example.com'
    const handler = makePatchUserEmail(repo);

    const req = makeReq({ id: '42', email: 'alice@example.com' }); // same email
    const res = makeRes();

    await handler(req, res);

    expect(res._status).toBe(200);
    expect(res._body).toEqual({ user: ALICE });
    expect(repo.updateEmail).not.toHaveBeenCalled();
    // Also must not check for conflicts — unnecessary DB call
    expect(repo.findByEmail).not.toHaveBeenCalled();
  });
});

// ---------------------------------------------------------------------------
// Priority / ordering edge cases
// ---------------------------------------------------------------------------

describe('Guard ordering', () => {
  it('validates email format BEFORE checking if user exists (AC3 takes priority over AC4)', async () => {
    const repo = makeRepo({ user: null }); // user doesn't exist either
    const handler = makePatchUserEmail(repo);

    const req = makeReq({ id: 'ghost', email: 'bad-email' });
    const res = makeRes();

    await handler(req, res);

    // Should still get 400, not 404
    expect(res._status).toBe(400);
    expect((res._body as { error: { code: string } }).error.code).toBe('INVALID_EMAIL_FORMAT');
    expect(repo.findById).not.toHaveBeenCalled();
  });
});

